const fs = require('fs');
const configPath = '/home/node/config/scrapers.json';

try {
  const raw = fs.readFileSync(configPath, 'utf-8');
  const config = JSON.parse(raw);
  const defaults = config.defaults || {};
  const promptTemplates = config.prompt_templates || {};

  const enabledSources = (config.sources || []).filter(
    s => s.enabled !== false && s.category === 'code'
  );

  return enabledSources.map(source => ({
    json: {
      ...source,
      model: source.model || defaults.model || 'anthropic/claude-3.5-sonnet',
      prompt_template: promptTemplates[source.prompt_template_key] || promptTemplates.code_trending || ''
    }
  }));
} catch (err) {
  console.error('Failed to read scrapers.json:', err.message);
  return [];
}

const source = $input.first().json;
const https = require('https');
const http = require('http');

function httpGet(url, headers = {}) {
  return new Promise((resolve, reject) => {
    const mod = url.startsWith('https') ? https : http;
    const req = mod.get(url, { headers }, (res) => {
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => {
        try { resolve(JSON.parse(data)); }
        catch(e) { reject(new Error('JSON parse error: ' + data.substring(0, 200))); }
      });
    });
    req.on('error', reject);
    req.setTimeout(30000, () => { req.destroy(); reject(new Error('Timeout')); });
  });
}

try {
  // Build URL with params
  const params = source.params || {};
  const yesterday = new Date(Date.now() - 86400000).toISOString().split('T')[0];
  const twoDaysAgo = new Date(Date.now() - 2 * 86400000).toISOString().split('T')[0];

  const urlParams = new URLSearchParams();
  for (const [key, val] of Object.entries(params)) {
    const resolved = String(val).replace(/\{yesterday\}/g, yesterday).replace(/\{two_days_ago\}/g, twoDaysAgo);
    urlParams.set(key, resolved);
  }

  const fullUrl = source.url + '?' + urlParams.toString();

  // Build headers
  const headers = { ...(source.headers || {}), 'User-Agent': 'DailyInfo-Bot/1.0' };

  // Add auth if configured
  if (source.auth_env) {
    const token = $env[source.auth_env];
    if (token) {
      headers['Authorization'] = 'token ' + token;
    }
  }

  const data = await httpGet(fullUrl, headers);

  // Extract items
  const extract = source.extract || {};
  let rawItems = extract.items_path ? data[extract.items_path] : data;

  if (!Array.isArray(rawItems)) {
    rawItems = [];
  }

  // Apply max_items limit
  const maxItems = source.max_items || 25;
  rawItems = rawItems.slice(0, maxItems);

  // Map fields
  const fields = extract.fields || {};
  const items = rawItems.map(item => {
    const mapped = {};
    for (const [outKey, srcKey] of Object.entries(fields)) {
      mapped[outKey] = item[srcKey] !== undefined ? item[srcKey] : null;
    }
    return mapped;
  });

  return [{
    json: {
      source_name: source.name,
      display_name: source.display_name,
      category: source.category,
      model: source.model,
      items: items,
      items_count: items.length,
      fetch_url: fullUrl
    }
  }];
} catch (err) {
  console.error(`Failed to fetch ${source.name}:`, err.message);
  return [{
    json: {
      source_name: source.name,
      display_name: source.display_name,
      category: source.category,
      model: source.model,
      items: [],
      items_count: 0,
      error: err.message
    }
  }];
}

const data = $input.first().json;
const items = data.items;
const displayName = data.display_name;

// Format items for AI prompt based on source type
let itemsList;
if (data.source_name === 'github_trending') {
  itemsList = items.map((item, i) => {
    const lang = item.language ? ` [${item.language}]` : '';
    const desc = item.description || 'No description';
    return `${i + 1}. **${item.name}**${lang} (⭐ ${item.stars}) — ${desc}\n   ${item.url || ''}`;
  }).join('\n');
} else if (data.source_name === 'huggingface_models') {
  itemsList = items.map((item, i) => {
    const task = item.task ? ` (${item.task})` : '';
    return `${i + 1}. **${item.name}**${task} — ❤️ ${item.likes || 0}, ⬇️ ${item.downloads || 0}`;
  }).join('\n');
} else if (data.source_name === 'huggingface_datasets') {
  itemsList = items.map((item, i) => {
    return `${i + 1}. **${item.name}** — ❤️ ${item.likes || 0}, ⬇️ ${item.downloads || 0}`;
  }).join('\n');
} else if (data.source_name === 'huggingface_spaces') {
  itemsList = items.map((item, i) => {
    const sdk = item.sdk ? ` [${item.sdk}]` : '';
    return `${i + 1}. **${item.name}**${sdk} — ❤️ ${item.likes || 0}`;
  }).join('\n');
} else {
  itemsList = items.map((item, i) => `${i + 1}. ${JSON.stringify(item)}`).join('\n');
}

const prompt = `你是一位资深技术编辑。请为以下 ${displayName} 的每个项目生成一句话中文摘要（突出核心功能/亮点）。\n\n${itemsList}\n\n要求：\n- 保留原始编号和项目名\n- 每个项目一行，格式为：编号. **项目名** — 一句话中文描述\n- 简洁精准，突出技术价值和创新点\n- 如果是代码项目，说明解决什么问题\n- 如果是模型/数据集，说明适用场景`;

const date = new Date().toISOString().split('T')[0];

return [{
  json: {
    source_name: data.source_name,
    display_name: data.display_name,
    category: data.category,
    model: data.model,
    prompt: prompt,
    items_count: data.items_count,
    date: date
  }
}];

const source = $('Build Prompt').item.json;
const response = $input.first().json;
const content = response.choices[0].message.content;
const date = source.date;
const category = source.category;
const name = source.source_name;

const fileName = `${name}_trending_${date}.md`;
const dirPath = `/home/node/workspace/briefings/${category}`;
const filePath = `${dirPath}/${fileName}`;

// Build final markdown with header
const header = `# ${source.display_name} — ${date}\n\n`;
const finalContent = header + content + '\n';

return [{
  json: {
    filePath: filePath,
    dirPath: dirPath,
    content: finalContent,
    source_name: name,
    category: category,
    date: date,
    items_count: source.items_count
  }
}];

const data = $input.first().json;
const fs = require('fs');
const path = require('path');

// Ensure directory exists
if (!fs.existsSync(data.dirPath)) {
  fs.mkdirSync(data.dirPath, { recursive: true });
}

fs.writeFileSync(data.filePath, data.content, 'utf-8');

return [{
  json: {
    success: true,
    filePath: data.filePath,
    source_name: data.source_name,
    category: data.category,
    date: data.date,
    items_count: data.items_count
  }
}];

const source = $input.first().json;
console.log(`Skipped ${source.source_name}: no items or fetch error`);
return [{ json: { skipped: source.source_name, reason: source.error || 'no items' } }];
